import React, { useEffect, useState } from 'react';

import { BrowserRouter as Router, Route } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css'; // Optional: For toast notifications
import "./styles/styles.css";

// Importing components
import Navbar from './components/Navbar.js';
import HomePage from './pages/HomePage.jsx';
import LoginPage from './pages/LoginPage.jsx';
import DashboardPage from './pages/DashboardPage.jsx';
import TransactionPage from './pages/TransactionPage.jsx';
import ProfilePage from './pages/ProfilePage.jsx';
import NotFoundPage from './pages/NotFoundPage.jsx';

// Importing context
import { AuthProvider } from './context/AuthContext.js';

function App() {
    const [isAuthenticated, setIsAuthenticated] = useState(false);

    // This effect is used to check if the user is authenticated (you could also check from localStorage or cookies)
    useEffect(() => {
        const token = localStorage.getItem('token');  // If you're using cookies, you could check the cookies here
        if (token) {
            setIsAuthenticated(true);
        } else {
            setIsAuthenticated(false);
        }
    }, []);

    return (
        <AuthProvider>
            <Router>
                <Navbar isAuthenticated={isAuthenticated} /> {/* Navbar will display based on authentication */}

                {/* Toast container for showing notifications */}
                <ToastContainer />

                {/* Routes for different pages */}
                <div className="container">
                    {/*<Switch>*/}
                        {/* Public routes */}
                        <Route exact path="/" component={HomePage} />
                        <Route path="/login" component={LoginPage} />

                        {/* Protected routes (only accessible if authenticated) */}
                        <PrivateRoute path="/dashboard" component={DashboardPage} isAuthenticated={isAuthenticated} />
                        <PrivateRoute path="/transactions" component={TransactionPage} isAuthenticated={isAuthenticated} />
                        <PrivateRoute path="/profile" component={ProfilePage} isAuthenticated={isAuthenticated} />

                        {/* Fallback route */}
                        <Route component={NotFoundPage} />
                    {/*</Switch>*/}
                </div>
            </Router>
        </AuthProvider>
    );
}

// PrivateRoute component to protect private pages (redirect to login if not authenticated)
function PrivateRoute({ component: Component, isAuthenticated, ...rest }) {
    return (
        <Route
            {...rest}
            render={(props) =>
                isAuthenticated ? (
                    <Component {...props} />
                ) : (
                    // Redirect to login page if not authenticated
                    <LoginPage />
                )
            }
        />
    );
}

export default App;


